def solve(eye_opening_score, verbal_response_score, motor_response_score):
    # Step 1: compute_gcs_score - Calculate total GCS score handling special cases
    if eye_opening_score == 'C':
        # If eye opening is not testable, return string with modifier
        total_gcs_score = f"{motor_response_score}+{verbal_response_score}+C"
    else:
        # Otherwise, sum the three integer components
        total = int(eye_opening_score) + verbal_response_score + motor_response_score
        total_gcs_score = str(total)

    yield {
        "step_name": "compute_gcs_score",
        "step_description": "Sum eye opening, verbal response, and motor response scores to compute total GCS. Handles the 'C' modifier by reporting as a component score, not a total sum.",
        "step_result": total_gcs_score,
        "unit": None
    }

    return total_gcs_score
